body:
I wrote a stepper motor position driver, which triggers on a gated clk with variable frequency.
Testing the module directly yields the expected result, but as soon, I test it with a gated clock (additionally with a frequency change), the module triggers on a not available posedge.

### Can you attach an example that shows the issue?  (Must be openly licensed, ideally in test_regress format.)
I only can show the module where it fails and a direct testcase, the code, generating the gated clock with variable frequency can't be shared.

```
// Copyright (c) 2024 Fabian Keßler

`default_nettype none
`include "autofokus_ports.svh"
import af::*;

module mk_stepper_motor_position (
  input  var logic        clk_control,          // Motor step trigger
  input  var logic        rst_n,                // Active-low reset signal
  input  var logic        i_direction,          // Direction signal
  input  var logic        i_reset_zero,         // Reset position to zero
  output var logic        o_reset_zero_acq,
  output var logic [17:0] o_current_position    // Current position
);

position_t current_position_reg, next_pos;

  always_ff @(posedge i_reset_zero, negedge i_reset_zero)
    o_reset_zero_acq <= i_reset_zero;

  always_ff @(posedge clk_control, negedge rst_n, posedge i_reset_zero) begin
    if (!rst_n || i_reset_zero) begin
      // Asynchronous Reset: Initialize on reset
      current_position_reg <= 18'h0;
    end else begin
      current_position_reg <= current_position_reg + ((i_direction != 0) ? -1: 1);
    end
  end

  assign o_current_position = current_position_reg;

endmodule

```

```
// Copyright (c) 2024 Fabian Keßler

module tb_mk_stepper_motor_position;
  parameter CLK_PERIOD = 2;  // Clock period in ns

  // Signal declarations
  logic clk;                // Clock signal
  logic gated;
  logic enable;
  logic reset;              // Reset signal
  logic [17:0] position;    // Output position signal

  // Instantiate the mk_steper_motor_position module
  mk_stepper_motor_position uut (
    .clk_control(gated),
    .rst_n(reset),
    .i_direction(0),
    .i_reset_zero(0),
    .o_reset_zero_acq(),
    .o_current_position(position)
  );

  assign gated = enable? clk: 0; 

  initial begin
    clk = 0;
    forever #(CLK_PERIOD / 2) clk = ~clk;  // Clock toggles every half-period
  end

  initial begin
    $dumpfile("tb_mk_stepper_moter_position.vcd");
    $dumpvars;

    enable = 0;
    reset = 1;
  
    #20 reset = 0;
    #20 reset = 1;

    #(CLK_PERIOD * 3) enable = 1;
    #(CLK_PERIOD * 3) enable = 0;
    #(CLK_PERIOD * 3);
    #(CLK_PERIOD * 3);

    $finish;
  end

endmodule
```
